#include <stdlib.h>
#include <stdio.h>

#include "../common.h"
#include "../util/timer/timer.h"

#include "./kernel_cpu.h"
#include "./kernel_gpu_cuda_wrapper.h"

void
kernel_cpu(	int cores_arg,
			record *records,
			knode *knodes,
			long knodes_elem,
			int order,
			long maxheight,
			int count,
			long *currKnode,
			long *offset,
			int *keys,
			record *ans)
{
	(void)cores_arg;

	long long time0;
	long long time1;
	long long time2;

	time0 = get_time();

	int threadsPerBlock;
	threadsPerBlock = order < 1024 ? order : 1024;
	(void)threadsPerBlock;

	time1 = get_time();

	long records_mem = (long)((char*)knodes - (char*)records);
	long knodes_mem = knodes_elem * (long)sizeof(knode);

	kernel_gpu_cuda_wrapper(records,
							records_mem,
							knodes,
							knodes_elem,
							knodes_mem,
							order,
							maxheight,
							count,
							currKnode,
							offset,
							keys,
							ans);

	time2 = get_time();

	printf("Time spent in different stages of CPU/MCPU KERNEL:\n");
	printf("%15.12f s, %15.12f % : MCPU: SET DEVICE\n",
			(float)(time1 - time0) / 1000000,
			(float)(time1 - time0) / (float)(time2 - time0) * 100);
	printf("%15.12f s, %15.12f % : CPU/MCPU: KERNEL\n",
			(float)(time2 - time1) / 1000000,
			(float)(time2 - time1) / (float)(time2 - time0) * 100);

	printf("Total time:\n");
	printf("%.12f s\n", (float)(time2 - time0) / 1000000);
}

