#include <cuda_runtime.h>
#include <stdio.h>

#include "../common.h"
#include "./kernel_gpu_cuda_wrapper.h"

__global__ static void find_k_kernel(record *records,
									 knode *knodes,
									 long knodes_elem,
									 int order,
									 long maxheight,
									 int count,
									 long *currKnode,
									 long *offset,
									 int *keys,
									 record *ans)
{
	int bid = blockIdx.x * blockDim.x + threadIdx.x;
	if (bid >= count) return;

	int threadsPerBlock = order < 1024 ? order : 1024;

	for (long i = 0; i < maxheight; i++) {
		for (int thid = 0; thid < threadsPerBlock; thid++) {
			if ((knodes[currKnode[bid]].keys[thid] <= keys[bid]) &&
				(knodes[currKnode[bid]].keys[thid + 1] > keys[bid])) {
				if (knodes[offset[bid]].indices[thid] < knodes_elem) {
					offset[bid] = knodes[offset[bid]].indices[thid];
				}
			}
		}
		currKnode[bid] = offset[bid];
	}

	for (int thid = 0; thid < threadsPerBlock; thid++) {
		if (knodes[currKnode[bid]].keys[thid] == keys[bid]) {
			ans[bid].value = records[knodes[currKnode[bid]].indices[thid]].value;
		}
	}
}

void
kernel_gpu_cuda_wrapper(record *records,
						long records_mem,
						knode *knodes,
						long knodes_elem,
						long knodes_mem,
						int order,
						long maxheight,
						int count,
						long *currKnode,
						long *offset,
						int *keys,
						record *ans)
{
	record *d_records = NULL;
	knode *d_knodes = NULL;
	long *d_currKnode = NULL;
	long *d_offset = NULL;
	int *d_keys = NULL;
	record *d_ans = NULL;

	cudaMalloc((void **)&d_records, (size_t)records_mem);
	cudaMalloc((void **)&d_knodes, (size_t)knodes_mem);
	cudaMalloc((void **)&d_currKnode, (size_t)(count * sizeof(long)));
	cudaMalloc((void **)&d_offset, (size_t)(count * sizeof(long)));
	cudaMalloc((void **)&d_keys, (size_t)(count * sizeof(int)));
	cudaMalloc((void **)&d_ans, (size_t)(count * sizeof(record)));

	cudaMemcpy(d_records, records, (size_t)records_mem, cudaMemcpyHostToDevice);
	cudaMemcpy(d_knodes, knodes, (size_t)knodes_mem, cudaMemcpyHostToDevice);
	cudaMemcpy(d_currKnode, currKnode, (size_t)(count * sizeof(long)), cudaMemcpyHostToDevice);
	cudaMemcpy(d_offset, offset, (size_t)(count * sizeof(long)), cudaMemcpyHostToDevice);
	cudaMemcpy(d_keys, keys, (size_t)(count * sizeof(int)), cudaMemcpyHostToDevice);
	cudaMemcpy(d_ans, ans, (size_t)(count * sizeof(record)), cudaMemcpyHostToDevice);

	int threads = 256;
	int blocks = (count + threads - 1) / threads;

	find_k_kernel<<<blocks, threads>>>(d_records, d_knodes, knodes_elem, order, maxheight, count,
									   d_currKnode, d_offset, d_keys, d_ans);
	cudaDeviceSynchronize();

	cudaMemcpy(ans, d_ans, (size_t)(count * sizeof(record)), cudaMemcpyDeviceToHost);

	cudaFree(d_records);
	cudaFree(d_knodes);
	cudaFree(d_currKnode);
	cudaFree(d_offset);
	cudaFree(d_keys);
	cudaFree(d_ans);
}

