extern "C" void setdevice(void);
extern "C" void checkCUDAError(const char *msg);

extern long size;

__global__ void kernel_search_points(record *records,
                                     knode *knodes,
                                     long knodes_elem,
                                     int order,
                                     long maxheight,
                                     int count,
                                     long *currKnode,
                                     long *offset,
                                     int *keys,
                                     record *ans,
                                     int threadsPerBlock) {
    int bid = blockIdx.x * blockDim.x + threadIdx.x;
    if (bid >= count) return;

    for (long i = 0; i < maxheight; i++) {
        for (int thid = 0; thid < threadsPerBlock; thid++) {
            if ((knodes[currKnode[bid]].keys[thid]) <= keys[bid] &&
                (knodes[currKnode[bid]].keys[thid + 1] > keys[bid])) {
                if (knodes[offset[bid]].indices[thid] < knodes_elem) {
                    offset[bid] = knodes[offset[bid]].indices[thid];
                }
            }
        }
        currKnode[bid] = offset[bid];
    }

    for (int thid = 0; thid < threadsPerBlock; thid++) {
        if (knodes[currKnode[bid]].keys[thid] == keys[bid]) {
            ans[bid].value = records[knodes[currKnode[bid]].indices[thid]].value;
        }
    }
}

void
kernel_cpu( int cores_arg,
            record *records,
            knode *knodes,
            long knodes_elem,
            int order,
            long maxheight,
            int count,
            long *currKnode,
            long *offset,
            int *keys,
            record *ans) {

    (void)cores_arg;

    long long time0;
    long long time1;
    long long time2;

    time0 = get_time();

    setdevice();

    int threadsPerBlock = order < 1024 ? order : 1024;
    if (threadsPerBlock <= 0) threadsPerBlock = 1;

    record *d_records = NULL;
    knode *d_knodes = NULL;
    long *d_currKnode = NULL;
    long *d_offset = NULL;
    int *d_keys = NULL;
    record *d_ans = NULL;

    cudaMalloc((void **)&d_records, sizeof(record) * (size_t)size);
    cudaMalloc((void **)&d_knodes, sizeof(knode) * (size_t)knodes_elem);
    cudaMalloc((void **)&d_currKnode, sizeof(long) * (size_t)count);
    cudaMalloc((void **)&d_offset, sizeof(long) * (size_t)count);
    cudaMalloc((void **)&d_keys, sizeof(int) * (size_t)count);
    cudaMalloc((void **)&d_ans, sizeof(record) * (size_t)count);
    checkCUDAError("CUDA malloc");

    cudaMemcpy(d_records, records, sizeof(record) * (size_t)size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_knodes, knodes, sizeof(knode) * (size_t)knodes_elem, cudaMemcpyHostToDevice);
    cudaMemcpy(d_currKnode, currKnode, sizeof(long) * (size_t)count, cudaMemcpyHostToDevice);
    cudaMemcpy(d_offset, offset, sizeof(long) * (size_t)count, cudaMemcpyHostToDevice);
    cudaMemcpy(d_keys, keys, sizeof(int) * (size_t)count, cudaMemcpyHostToDevice);
    cudaMemcpy(d_ans, ans, sizeof(record) * (size_t)count, cudaMemcpyHostToDevice);
    checkCUDAError("CUDA memcpy H2D");

    time1 = get_time();

    int blockSize = 256;
    int gridSize = (count + blockSize - 1) / blockSize;

    kernel_search_points<<<gridSize, blockSize>>>(d_records,
                                                  d_knodes,
                                                  knodes_elem,
                                                  order,
                                                  maxheight,
                                                  count,
                                                  d_currKnode,
                                                  d_offset,
                                                  d_keys,
                                                  d_ans,
                                                  threadsPerBlock);
    cudaDeviceSynchronize();
    checkCUDAError("CUDA kernel_search_points");

    cudaMemcpy(ans, d_ans, sizeof(record) * (size_t)count, cudaMemcpyDeviceToHost);
    checkCUDAError("CUDA memcpy D2H");

    cudaFree(d_records);
    cudaFree(d_knodes);
    cudaFree(d_currKnode);
    cudaFree(d_offset);
    cudaFree(d_keys);
    cudaFree(d_ans);

    time2 = get_time();

    printf("Time spent in different stages of CPU/MCPU KERNEL:\n");
    printf("%15.12f s, %15.12f % : MCPU: SET DEVICE\n",
           (float)(time1 - time0) / 1000000,
           (float)(time1 - time0) / (float)(time2 - time0) * 100);
    printf("%15.12f s, %15.12f % : CPU/MCPU: KERNEL\n",
           (float)(time2 - time1) / 1000000,
           (float)(time2 - time1) / (float)(time2 - time0) * 100);

    printf("Total time:\n");
    printf("%.12f s\n", (float)(time2 - time0) / 1000000);
}

