__global__ static void layerforward_kernel(const float *l1, float *l2, const float *conn, int n1, int n2) {
  int j = blockIdx.x * blockDim.x + threadIdx.x + 1;
  if (j <= n2) {
    float sum = 0.0f;
    int stride = n2 + 1;
    for (int k = 0; k <= n1; k++) {
      sum += conn[k * stride + j] * l1[k];
    }
    l2[j] = 1.0f / (1.0f + expf(-sum));
  }
}

__global__ static void adjust_weights_kernel(float *delta, int ndelta, float *ly, int nly, float *w, float *oldw) {
  int idx = blockIdx.x * blockDim.x + threadIdx.x;
  int cols = nly + 1;
  int total = ndelta * cols;
  if (idx < total) {
    int j = idx / cols + 1;
    int k = idx % cols;
    int stride = ndelta + 1;
    int pos = k * stride + j;
    float new_dw = ((ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[pos]));
    w[pos] += new_dw;
    oldw[pos] = new_dw;
  }
}

