extern "C" void bpnn_layerforward(float *l1, float *l2, float **conn, int n1, int n2) {
  l1[0] = 1.0f;

  int rows = n1 + 1;
  int cols = n2 + 1;
  float *h_conn = flatten_matrix(conn, rows, cols);
  if (!h_conn) return;

  float *d_l1 = NULL, *d_l2 = NULL, *d_conn = NULL;
  cuda_check(cudaMalloc((void **)&d_l1, rows * sizeof(float)));
  cuda_check(cudaMalloc((void **)&d_l2, cols * sizeof(float)));
  cuda_check(cudaMalloc((void **)&d_conn, rows * cols * sizeof(float)));

  cuda_check(cudaMemcpy(d_l1, l1, rows * sizeof(float), cudaMemcpyHostToDevice));
  cuda_check(cudaMemcpy(d_l2, l2, cols * sizeof(float), cudaMemcpyHostToDevice));
  cuda_check(cudaMemcpy(d_conn, h_conn, rows * cols * sizeof(float), cudaMemcpyHostToDevice));

  int threads = 256;
  int blocks = (n2 + threads - 1) / threads;
  layerforward_kernel<<<blocks, threads>>>(d_l1, d_l2, d_conn, n1, n2);
  cuda_check(cudaDeviceSynchronize());

  cuda_check(cudaMemcpy(l2, d_l2, cols * sizeof(float), cudaMemcpyDeviceToHost));

  cudaFree(d_l1);
  cudaFree(d_l2);
  cudaFree(d_conn);
  free(h_conn);
}

extern "C" void bpnn_output_error(float *delta, float *target, float *output, int nj, float *err) {
  float errsum = 0.0f;
  for (int j = 1; j <= nj; j++) {
    float o = output[j];
    float t = target[j];
    delta[j] = o * (1.0f - o) * (t - o);
    errsum += ABS(delta[j]);
  }
  *err = errsum;
}

extern "C" void bpnn_hidden_error(float *delta_h, int nh, float *delta_o, int no, float **who, float *hidden, float *err) {
  float errsum = 0.0f;
  for (int j = 1; j <= nh; j++) {
    float h = hidden[j];
    float sum = 0.0f;
    for (int k = 1; k <= no; k++) {
      sum += delta_o[k] * who[j][k];
    }
    delta_h[j] = h * (1.0f - h) * sum;
    errsum += ABS(delta_h[j]);
  }
  *err = errsum;
}

extern "C" void bpnn_adjust_weights(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw) {
  ly[0] = 1.0f;

  int rows = nly + 1;
  int cols = ndelta + 1;
  float *h_w = flatten_matrix(w, rows, cols);
  float *h_oldw = flatten_matrix(oldw, rows, cols);
  if (!h_w || !h_oldw) {
    if (h_w) free(h_w);
    if (h_oldw) free(h_oldw);
    return;
  }

  float *d_delta = NULL, *d_ly = NULL, *d_w = NULL, *d_oldw = NULL;
  cuda_check(cudaMalloc((void **)&d_delta, (ndelta + 1) * sizeof(float)));
  cuda_check(cudaMalloc((void **)&d_ly, (nly + 1) * sizeof(float)));
  cuda_check(cudaMalloc((void **)&d_w, rows * cols * sizeof(float)));
  cuda_check(cudaMalloc((void **)&d_oldw, rows * cols * sizeof(float)));

  cuda_check(cudaMemcpy(d_delta, delta, (ndelta + 1) * sizeof(float), cudaMemcpyHostToDevice));
  cuda_check(cudaMemcpy(d_ly, ly, (nly + 1) * sizeof(float), cudaMemcpyHostToDevice));
  cuda_check(cudaMemcpy(d_w, h_w, rows * cols * sizeof(float), cudaMemcpyHostToDevice));
  cuda_check(cudaMemcpy(d_oldw, h_oldw, rows * cols * sizeof(float), cudaMemcpyHostToDevice));

  int total = ndelta * (nly + 1);
  int threads = 256;
  int blocks = (total + threads - 1) / threads;
  adjust_weights_kernel<<<blocks, threads>>>(d_delta, ndelta, d_ly, nly, d_w, d_oldw);
  cuda_check(cudaDeviceSynchronize());

  cuda_check(cudaMemcpy(h_w, d_w, rows * cols * sizeof(float), cudaMemcpyDeviceToHost));
  cuda_check(cudaMemcpy(h_oldw, d_oldw, rows * cols * sizeof(float), cudaMemcpyDeviceToHost));

  scatter_matrix(w, h_w, rows, cols);
  scatter_matrix(oldw, h_oldw, rows, cols);

  cudaFree(d_delta);
  cudaFree(d_ly);
  cudaFree(d_w);
  cudaFree(d_oldw);
  free(h_w);
  free(h_oldw);
}

extern "C" void bpnn_feedforward(BPNN *net) {
  int in = net->input_n;
  int hid = net->hidden_n;
  int out = net->output_n;

  bpnn_layerforward(net->input_units, net->hidden_units, net->input_weights, in, hid);
  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
}

extern "C" void bpnn_train(BPNN *net, float *eo, float *eh) {
  int in = net->input_n;
  int hid = net->hidden_n;
  int out = net->output_n;
  float out_err, hid_err;

  bpnn_layerforward(net->input_units, net->hidden_units, net->input_weights, in, hid);
  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);

  bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
  bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights, net->hidden_units, &hid_err);
  *eo = out_err;
  *eh = hid_err;

  bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights, net->hidden_prev_weights);
  bpnn_adjust_weights(net->hidden_delta, hid, net->input_units, in, net->input_weights, net->input_prev_weights);
}

extern "C" void bpnn_save(BPNN *net, char *filename) {
  int n1, n2, n3, i, j, memcnt;
  float dvalue, **w;
  char *mem;

  FILE *pFile;
  pFile = fopen(filename, "w+");

  n1 = net->input_n;
  n2 = net->hidden_n;
  n3 = net->output_n;
  printf("Saving %dx%dx%d network to '%s'\n", n1, n2, n3, filename);

  fwrite((char *)&n1, sizeof(char), sizeof(char), pFile);
  fwrite((char *)&n2, sizeof(char), sizeof(char), pFile);
  fwrite((char *)&n3, sizeof(char), sizeof(char), pFile);

  memcnt = 0;
  w = net->input_weights;
  mem = (char *)malloc((unsigned)((n1 + 1) * (n2 + 1) * sizeof(float)));
  for (i = 0; i <= n1; i++) {
    for (j = 0; j <= n2; j++) {
      dvalue = w[i][j];
      fastcopy(&mem[memcnt], &dvalue, sizeof(float));
      memcnt += sizeof(float);
    }
  }

  fwrite(mem, (unsigned)(sizeof(float)), (unsigned)((n1 + 1) * (n2 + 1) * sizeof(float)), pFile);
  free(mem);

  memcnt = 0;
  w = net->hidden_weights;
  mem = (char *)malloc((unsigned)((n2 + 1) * (n3 + 1) * sizeof(float)));
  for (i = 0; i <= n2; i++) {
    for (j = 0; j <= n3; j++) {
      dvalue = w[i][j];
      fastcopy(&mem[memcnt], &dvalue, sizeof(float));
      memcnt += sizeof(float);
    }
  }

  fwrite(mem, sizeof(float), (unsigned)((n2 + 1) * (n3 + 1) * sizeof(float)), pFile);
  free(mem);

  fclose(pFile);
  return;
}

extern "C" BPNN *bpnn_read(char *filename) {
  char *mem;
  BPNN *newnet;
  int fd, n1, n2, n3, i, j, memcnt;

  if ((fd = open(filename, 0, 0644)) == -1) {
    return NULL;
  }

  printf("Reading '%s'\n", filename);

  read(fd, (char *)&n1, sizeof(int));
  read(fd, (char *)&n2, sizeof(int));
  read(fd, (char *)&n3, sizeof(int));
  newnet = bpnn_internal_create(n1, n2, n3);

  printf("'%s' contains a %dx%dx%d network\n", filename, n1, n2, n3);
  printf("Reading input weights...");

  memcnt = 0;
  mem = (char *)malloc((unsigned)((n1 + 1) * (n2 + 1) * sizeof(float)));
  read(fd, mem, (n1 + 1) * (n2 + 1) * sizeof(float));
  for (i = 0; i <= n1; i++) {
    for (j = 0; j <= n2; j++) {
      fastcopy(&(newnet->input_weights[i][j]), &mem[memcnt], sizeof(float));
      memcnt += sizeof(float);
    }
  }
  free(mem);

  printf("Done\nReading hidden weights...");

  memcnt = 0;
  mem = (char *)malloc((unsigned)((n2 + 1) * (n3 + 1) * sizeof(float)));
  read(fd, mem, (n2 + 1) * (n3 + 1) * sizeof(float));
  for (i = 0; i <= n2; i++) {
    for (j = 0; j <= n3; j++) {
      fastcopy(&(newnet->hidden_weights[i][j]), &mem[memcnt], sizeof(float));
      memcnt += sizeof(float);
    }
  }
  free(mem);
  close(fd);

  printf("Done\n");

  bpnn_zero_weights(newnet->input_prev_weights, n1, n2);
  bpnn_zero_weights(newnet->hidden_prev_weights, n2, n3);

  return newnet;
}

