static __device__ float squash_dev(float x) {
  return 1.0f / (1.0f + expf(-x));
}

static __global__ void layerforward_kernel(const float *l1, float *l2, const float *conn, int n1, int n2) {
  int j = blockIdx.x * blockDim.x + threadIdx.x + 1;
  if (j <= n2) {
    float sum = 0.0f;
    for (int k = 0; k <= n1; k++) {
      sum += conn[k * (n2 + 1) + j] * l1[k];
    }
    l2[j] = squash_dev(sum);
  }
}

static __global__ void adjust_weights_kernel(const float *delta, int ndelta, const float *ly, int nly, float *w, float *oldw) {
  int j = blockIdx.x * blockDim.x + threadIdx.x + 1;
  int k = blockIdx.y * blockDim.y + threadIdx.y;
  if (j <= ndelta && k <= nly) {
    int idx = k * (ndelta + 1) + j;
    float new_dw = (ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[idx]);
    w[idx] += new_dw;
    oldw[idx] = new_dw;
  }
}

static void flatten_2d(float **src, int rows, int cols, float *dst) {
  for (int i = 0; i <= rows; i++) {
    for (int j = 0; j <= cols; j++) {
      dst[i * (cols + 1) + j] = src[i][j];
    }
  }
}

static void unflatten_2d(float *src, int rows, int cols, float **dst) {
  for (int i = 0; i <= rows; i++) {
    for (int j = 0; j <= cols; j++) {
      dst[i][j] = src[i * (cols + 1) + j];
    }
  }
}

