extern "C" void bpnn_layerforward(float *l1, float *l2, float **conn, int n1, int n2) {
  l1[0] = 1.0f;

  size_t l1_size = (size_t)(n1 + 1) * sizeof(float);
  size_t l2_size = (size_t)(n2 + 1) * sizeof(float);
  size_t conn_size = (size_t)(n1 + 1) * (size_t)(n2 + 1) * sizeof(float);

  float *conn_flat = (float *)malloc(conn_size);
  flatten_2d(conn, n1, n2, conn_flat);

  float *d_l1 = NULL, *d_l2 = NULL, *d_conn = NULL;
  cudaMalloc((void **)&d_l1, l1_size);
  cudaMalloc((void **)&d_l2, l2_size);
  cudaMalloc((void **)&d_conn, conn_size);

  cudaMemcpy(d_l1, l1, l1_size, cudaMemcpyHostToDevice);
  cudaMemcpy(d_l2, l2, l2_size, cudaMemcpyHostToDevice);
  cudaMemcpy(d_conn, conn_flat, conn_size, cudaMemcpyHostToDevice);

  int block = 256;
  int grid = (n2 + block - 1) / block;
  layerforward_kernel<<<grid, block>>>(d_l1, d_l2, d_conn, n1, n2);

  cudaMemcpy(l2, d_l2, l2_size, cudaMemcpyDeviceToHost);

  cudaFree(d_l1);
  cudaFree(d_l2);
  cudaFree(d_conn);
  free(conn_flat);
