extern "C" void bpnn_output_error(float *delta, float *target, float *output, int nj, float *err) {
  float errsum = 0.0f;
  for (int j = 1; j <= nj; j++) {
    float o = output[j];
    float t = target[j];
    delta[j] = o * (1.0f - o) * (t - o);
    errsum += ABS(delta[j]);
  }
  *err = errsum;
}

extern "C" void bpnn_hidden_error(float *delta_h, int nh, float *delta_o, int no, float **who, float *hidden, float *err) {
  float errsum = 0.0f;
  for (int j = 1; j <= nh; j++) {
    float h = hidden[j];
    float sum = 0.0f;
    for (int k = 1; k <= no; k++) {
      sum += delta_o[k] * who[j][k];
    }
    delta_h[j] = h * (1.0f - h) * sum;
    errsum += ABS(delta_h[j]);
  }
  *err = errsum;
}

extern "C" void bpnn_adjust_weights(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw) {
  ly[0] = 1.0f;

  size_t delta_size = (size_t)(ndelta + 1) * sizeof(float);
  size_t ly_size = (size_t)(nly + 1) * sizeof(float);
  size_t mat_size = (size_t)(nly + 1) * (size_t)(ndelta + 1) * sizeof(float);

  float *w_flat = (float *)malloc(mat_size);
  float *oldw_flat = (float *)malloc(mat_size);
  flatten_2d(w, nly, ndelta, w_flat);
  flatten_2d(oldw, nly, ndelta, oldw_flat);

  float *d_delta = NULL, *d_ly = NULL, *d_w = NULL, *d_oldw = NULL;
  cudaMalloc((void **)&d_delta, delta_size);
  cudaMalloc((void **)&d_ly, ly_size);
  cudaMalloc((void **)&d_w, mat_size);
  cudaMalloc((void **)&d_oldw, mat_size);

  cudaMemcpy(d_delta, delta, delta_size, cudaMemcpyHostToDevice);
  cudaMemcpy(d_ly, ly, ly_size, cudaMemcpyHostToDevice);
  cudaMemcpy(d_w, w_flat, mat_size, cudaMemcpyHostToDevice);
  cudaMemcpy(d_oldw, oldw_flat, mat_size, cudaMemcpyHostToDevice);

  dim3 block(16, 16);
  dim3 grid((ndelta + block.x - 1) / block.x, ((nly + 1) + block.y - 1) / block.y);
  adjust_weights_kernel<<<grid, block>>>(d_delta, ndelta, d_ly, nly, d_w, d_oldw);

  cudaMemcpy(w_flat, d_w, mat_size, cudaMemcpyDeviceToHost);
  cudaMemcpy(oldw_flat, d_oldw, mat_size, cudaMemcpyDeviceToHost);

  unflatten_2d(w_flat, nly, ndelta, w);
  unflatten_2d(oldw_flat, nly, ndelta, oldw);

  cudaFree(d_delta);
  cudaFree(d_ly);
  cudaFree(d_w);
  cudaFree(d_oldw);
  free(w_flat);
  free(oldw_flat);
}

extern "C" void bpnn_feedforward(BPNN *net) {
