      fastcopy(&(nw->hidden_weights[i][j]), &mem[memcnt], sizeof(float));
      memcnt += sizeof(float);
    }
  }
  free(mem);
  close(fd);

  printf("Done\n");

  bpnn_zero_weights(nw->input_prev_weights, n1, n2);
  bpnn_zero_weights(nw->hidden_prev_weights, n2, n3);

  return nw;
}

