                           (temp[c + 1] + temp[c - 1] - 2.0f * temp[c]) * Rx_1 +
                           (temp[col + c] - temp[c]) * Ry_1 +
                           (amb_temp - temp[c]) * Rz_1);
    } else if (c == col - 1) {
        delta = (Cap_1) * (power[idx] +
                           (temp[(r + 1) * col + c] + temp[(r - 1) * col + c] - 2.0f * temp[idx]) * Ry_1 +
                           (temp[idx - 1] - temp[idx]) * Rx_1 +
                           (amb_temp - temp[idx]) * Rz_1);
    } else if (r == row - 1) {
        delta = (Cap_1) * (power[idx] +
                           (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
                           (temp[(r - 1) * col + c] - temp[idx]) * Ry_1 +
                           (amb_temp - temp[idx]) * Rz_1);
    } else if (c == 0) {
        delta = (Cap_1) * (power[r * col] +
                           (temp[(r + 1) * col] + temp[(r - 1) * col] - 2.0f * temp[r * col]) * Ry_1 +
                           (temp[r * col + 1] - temp[r * col]) * Rx_1 +
                           (amb_temp - temp[r * col]) * Rz_1);
    } else {
        delta = (Cap_1) * (power[idx] +
                           (temp[(r + 1) * col + c] + temp[(r - 1) * col + c] - 2.0f * temp[idx]) * Ry_1 +
                           (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
                           (amb_temp - temp[idx]) * Rz_1);
    }

    result[idx] = temp[idx] + delta;
}

void single_iteration(FLOAT *result, FLOAT *temp, FLOAT *power, int row, int col,
                      FLOAT Cap_1, FLOAT Rx_1, FLOAT Ry_1, FLOAT Rz_1,
                      FLOAT step)
{
    (void)step;
    dim3 block(BLOCK_SIZE_C, BLOCK_SIZE_R);
    dim3 grid((col + block.x - 1) / block.x, (row + block.y - 1) / block.y);
    hotspot_kernel<<<grid, block>>>(result, temp, power, row, col, Cap_1, Rx_1, Ry_1, Rz_1);
    CUDA_CHECK(cudaGetLastError());
}

void compute_tran_temp(FLOAT *result, int num_iterations, FLOAT *temp, FLOAT *power, int row, int col)
{
    FLOAT grid_height = chip_height / row;
    FLOAT grid_width = chip_width / col;

    FLOAT Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
    FLOAT Rx = grid_width / (2.0f * K_SI * t_chip * grid_height);
    FLOAT Ry = grid_height / (2.0f * K_SI * t_chip * grid_width);
    FLOAT Rz = t_chip / (K_SI * grid_height * grid_width);

    FLOAT max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    FLOAT step = PRECISION / max_slope / 1000.0f;

    FLOAT Rx_1 = 1.0f / Rx;
    FLOAT Ry_1 = 1.0f / Ry;
    FLOAT Rz_1 = 1.0f / Rz;
    FLOAT Cap_1 = step / Cap;

    size_t array_size = (size_t)row * (size_t)col * sizeof(FLOAT);

    FLOAT *d_temp = NULL, *d_power = NULL, *d_result = NULL;
    CUDA_CHECK(cudaMalloc((void **)&d_temp, array_size));
    CUDA_CHECK(cudaMalloc((void **)&d_power, array_size));
    CUDA_CHECK(cudaMalloc((void **)&d_result, array_size));

    CUDA_CHECK(cudaMemcpy(d_temp, temp, array_size, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_power, power, array_size, cudaMemcpyHostToDevice));

    FLOAT *t = d_temp;
    FLOAT *r = d_result;

    for (int i = 0; i < num_iterations; i++) {
        single_iteration(r, t, d_power, row, col, Cap_1, Rx_1, Ry_1, Rz_1, step);
        FLOAT *tmp = t;
        t = r;
        r = tmp;
    }

    CUDA_CHECK(cudaDeviceSynchronize());

    CUDA_CHECK(cudaMemcpy(temp, d_temp, array_size, cudaMemcpyDeviceToHost));
    CUDA_CHECK(cudaMemcpy(result, d_result, array_size, cudaMemcpyDeviceToHost));

    CUDA_CHECK(cudaFree(d_temp));
    CUDA_CHECK(cudaFree(d_power));
    CUDA_CHECK(cudaFree(d_result));
}

