#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <cuda_runtime.h>

#include "./main.h"
#include "./util/timer/timer.h"
#include "./device/device.h"

__global__ void kernel_gpu_cuda(box_str* box,
                                FOUR_VECTOR* rv,
                                fp* qv,
                                FOUR_VECTOR* fv,
                                fp a2,
                                long number_boxes) {
	int l = blockIdx.x;
	int i = threadIdx.x;

	if (l < number_boxes && i < NUMBER_PAR_PER_BOX) {
		int j, k;
		long first_i;
		int pointer;
		long first_j;

		fp r2;
		fp u2;
		fp fs;
		fp vij;
		fp fxij, fyij, fzij;
		THREE_VECTOR d;

		first_i = box[l].offset;

		FOUR_VECTOR rAi = rv[first_i + i];
		FOUR_VECTOR fAi = fv[first_i + i];

		for (k = 0; k < (1 + box[l].nn); k++) {
			if (k == 0) {
				pointer = l;
			} else {
				pointer = box[l].nei[k - 1].number;
			}

			first_j = box[pointer].offset;
			FOUR_VECTOR* rB = &rv[first_j];
			fp* qB = &qv[first_j];

			for (j = 0; j < NUMBER_PAR_PER_BOX; j++) {
				r2 = rAi.v + rB[j].v - (rAi.x * rB[j].x + rAi.y * rB[j].y + rAi.z * rB[j].z);
				u2 = a2 * r2;
				vij = exp(-u2);
				fs = 2.0 * vij;
				d.x = rAi.x - rB[j].x;
				d.y = rAi.y - rB[j].y;
				d.z = rAi.z - rB[j].z;
				fxij = fs * d.x;
				fyij = fs * d.y;
				fzij = fs * d.z;

				fAi.v += qB[j] * vij;
				fAi.x += qB[j] * fxij;
				fAi.y += qB[j] * fyij;
				fAi.z += qB[j] * fzij;
			}
		}

		fv[first_i + i] = fAi;
	}
}

void kernel_gpu_cuda_wrapper(par_str par_cpu,
                             dim_str dim_cpu,
                             box_str* box_cpu,
                             FOUR_VECTOR* rv_cpu,
                             fp* qv_cpu,
                             FOUR_VECTOR* fv_cpu) {
	long long time0;
	time0 = get_time();

	long long time1;
	long long time2;
	long long time3;
	long long time4;

	fp alpha;
	fp a2;

	box_str* d_box = NULL;
	FOUR_VECTOR* d_rv = NULL;
	fp* d_qv = NULL;
	FOUR_VECTOR* d_fv = NULL;

	time1 = get_time();

	setdevice();

	time2 = get_time();

	alpha = par_cpu.alpha;
	a2 = 2.0 * alpha * alpha;

	cudaMalloc((void**)&d_box, dim_cpu.box_mem);
	cudaMalloc((void**)&d_rv, dim_cpu.space_mem);
	cudaMalloc((void**)&d_qv, dim_cpu.space_mem2);
	cudaMalloc((void**)&d_fv, dim_cpu.space_mem);

	cudaMemcpy(d_box, box_cpu, dim_cpu.box_mem, cudaMemcpyHostToDevice);
	cudaMemcpy(d_rv, rv_cpu, dim_cpu.space_mem, cudaMemcpyHostToDevice);
	cudaMemcpy(d_qv, qv_cpu, dim_cpu.space_mem2, cudaMemcpyHostToDevice);
	cudaMemcpy(d_fv, fv_cpu, dim_cpu.space_mem, cudaMemcpyHostToDevice);

	time3 = get_time();

	dim3 blocks((unsigned int)dim_cpu.number_boxes, 1, 1);
	dim3 threads(NUMBER_PAR_PER_BOX, 1, 1);

	kernel_gpu_cuda<<<blocks, threads>>>(d_box, d_rv, d_qv, d_fv, a2, dim_cpu.number_boxes);
	checkCUDAError("kernel_gpu_cuda");
	cudaDeviceSynchronize();
	checkCUDAError("cudaDeviceSynchronize");

	cudaMemcpy(fv_cpu, d_fv, dim_cpu.space_mem, cudaMemcpyDeviceToHost);

	cudaFree(d_box);
	cudaFree(d_rv);
	cudaFree(d_qv);
	cudaFree(d_fv);

	time4 = get_time();

	printf("Time spent in different stages of CPU/MCPU KERNEL:\n");
	printf("%15.12f s, %15.12f % : CPU/MCPU: VARIABLES\n", (float)(time1 - time0) / 1000000, (float)(time1 - time0) / (float)(time4 - time0) * 100);
	printf("%15.12f s, %15.12f % : MCPU: SET DEVICE\n", (float)(time2 - time1) / 1000000, (float)(time2 - time1) / (float)(time4 - time0) * 100);
	printf("%15.12f s, %15.12f % : CPU/MCPU: INPUTS\n", (float)(time3 - time2) / 1000000, (float)(time3 - time2) / (float)(time4 - time0) * 100);
	printf("%15.12f s, %15.12f % : CPU/MCPU: KERNEL\n", (float)(time4 - time3) / 1000000, (float)(time4 - time3) / (float)(time4 - time0) * 100);

	printf("Total time:\n");
	printf("%.12f s\n", (float)(time4 - time0) / 1000000);
}

