func_ret_t
create_matrix(float **mp, int size){
  float *m;
  int i,j;
  float lamda = -0.001f;
  float *coe = (float*)malloc(sizeof(float) * (2 * size - 1));
  float coe_i =0.0f;

  if (coe == NULL) {
      return RET_FAILURE;
  }

  for (i=0; i < size; i++)
    {
      coe_i = 10.0f * expf(lamda*i);
