	fp J_ca2cam_SLmyo;
	fp J_ca4cam_SLmyo;

	BtotDyad      = parameter[2];
	CaMKIItotDyad = parameter[3];

	Vmyo = 2.1454e-11f;
	Vdyad = 1.7790e-14f;
	VSL = 6.6013e-13f;
