  fp J_SRleak = 5.348e-6f * (v[30] - v[35]);

  finavalu[o[16]] = kon_na * v[31] * (Bmax_Naj - v[16]) - koff_na * v[16];
  finavalu[o[17]] = kon_na * v[32] * (Bmax_Nasl - v[17]) - koff_na * v[17];

  finavalu[o[18]] = kon_tncl * v[37] * (Bmax_TnClow - v[18]) - koff_tncl * v[18];
  finavalu[o[19]] = kon_tnchca * v[37] * (Bmax_TnChigh - v[19] - v[20]) - koff_tnchca * v[19];
  finavalu[o[20]] = kon_tnchmg * Mgi * (Bmax_TnChigh - v[19] - v[20]) - koff_tnchmg * v[20];
  finavalu[o[21]] = 0;
  finavalu[o[22]] = kon_myoca * v[37] * (Bmax_myosin - v[22] - v[23]) - koff_myoca * v[22];
  finavalu[o[23]] = kon_myomg * Mgi * (Bmax_myosin - v[22] - v[23]) - koff_myomg * v[23];
  finavalu[o[24]] = kon_sr * v[37] * (Bmax_SR - v[24]) - koff_sr * v[24];
  fp J_CaB_cytosol = finavalu[o[18]] + finavalu[o[19]] + finavalu[o[20]] + finavalu[o[21]] + finavalu[o[22]] + finavalu[o[23]] + finavalu[o[24]];

  finavalu[o[25]] = kon_sll * v[35] * (Bmax_SLlowj - v[25]) - koff_sll * v[25];
  finavalu[o[26]] = kon_sll * v[36] * (Bmax_SLlowsl - v[26]) - koff_sll * v[26];
  finavalu[o[27]] = kon_slh * v[35] * (Bmax_SLhighj - v[27]) - koff_slh * v[27];
  finavalu[o[28]] = kon_slh * v[36] * (Bmax_SLhighsl - v[28]) - koff_slh * v[28];
  fp J_CaB_junction = finavalu[o[25]] + finavalu[o[27]];
  fp J_CaB_sl = finavalu[o[26]] + finavalu[o[28]];

  finavalu[o[29]] = kon_csqn * v[30] * (Bmax_Csqn - v[29]) - koff_csqn * v[29];
