  fp I_Na_tot_sl = I_Na_sl + I_nabk_sl + 3 * I_ncx_sl + 3 * I_nak_sl + I_CaNa_sl;
  finavalu[o[31]] = -I_Na_tot_junc * Cmem / (Vjunc * Frdy) + J_na_juncsl / Vjunc * (v[32] - v[31]) - finavalu[o[16]];
  fp oneovervsl = 1 / Vsl;
