  finavalu[o[36]] = -I_Ca_tot_sl * Cmem / (Vsl * 2 * Frdy) + J_ca_juncsl / Vsl * (v[35] - v[36]) + J_ca_slmyo / Vsl * (v[37] - v[36]) - J_CaB_sl;
  finavalu[o[37]] = -J_serca - J_CaB_cytosol + J_ca_slmyo / Vmyo * (v[36] - v[37]);

  int state = 1;
  fp I_app, V_hold, V_test, V_clamp, R_clamp;
  switch (state) {
    case 0: I_app = 0; break;
    case 1:
