  fp I_Cl_tot = I_ClCa + I_Clbk;
  fp I_Ca_tot = I_Ca_tot_junc + I_Ca_tot_sl;
  fp I_tot = I_Na_tot + I_Cl_tot + I_Ca_tot + I_K_tot;
  finavalu[o[38]] = -(I_tot - I_app);

  finavalu[o[40]] = 0;
  finavalu[o[41]] = 0;
}

__device__ void kernel_fin_2(fp timeinst,
                             fp *initvalu,
                             fp *finavalu,
                             int initvalu_offset_ecc,
                             int initvalu_offset_Dyad,
                             int initvalu_offset_SL,
                             int initvalu_offset_Cyt,
                             fp *parameter,
                             fp *com) {
  fp JCaDyad = com[0];
  fp JCaSL = com[1];
  fp JCaCyt = com[2];

  fp BtotDyad = parameter[2];
  fp CaMKIItotDyad = parameter[3];

  fp Vmyo = 2.1454e-11f, Vdyad = 1.7790e-14f, VSL = 6.6013e-13f, kDyadSL = 3.6363e-16f, kSLmyo = 8.587e-15f;
  fp k0Boff = 0.0014f, k0Bon = k0Boff / 0.2f, k2Boff = k0Boff / 100, k2Bon = k0Bon, k4Boff = k2Boff, k4Bon = k0Bon;

  finavalu[initvalu_offset_ecc + 35] = finavalu[initvalu_offset_ecc + 35] + 1e-3f * JCaDyad;
  finavalu[initvalu_offset_ecc + 36] = finavalu[initvalu_offset_ecc + 36] + 1e-3f * JCaSL;
  finavalu[initvalu_offset_ecc + 37] = finavalu[initvalu_offset_ecc + 37] + 1e-3f * JCaCyt;

  fp CaMtotDyad = initvalu[initvalu_offset_Dyad + 0] + initvalu[initvalu_offset_Dyad + 1] + initvalu[initvalu_offset_Dyad + 2] +
                  initvalu[initvalu_offset_Dyad + 3] + initvalu[initvalu_offset_Dyad + 4] + initvalu[initvalu_offset_Dyad + 5] +
                  CaMKIItotDyad * (initvalu[initvalu_offset_Dyad + 6] + initvalu[initvalu_offset_Dyad + 7] + initvalu[initvalu_offset_Dyad + 8] + initvalu[initvalu_offset_Dyad + 9]) +
                  initvalu[initvalu_offset_Dyad + 12] + initvalu[initvalu_offset_Dyad + 13] + initvalu[initvalu_offset_Dyad + 14];
  fp Bdyad = BtotDyad - CaMtotDyad;
  fp J_cam_dyadSL = 1e-3f * (k0Boff * initvalu[initvalu_offset_Dyad + 0] - k0Bon * Bdyad * initvalu[initvalu_offset_SL + 0]);
  fp J_ca2cam_dyadSL = 1e-3f * (k2Boff * initvalu[initvalu_offset_Dyad + 1] - k2Bon * Bdyad * initvalu[initvalu_offset_SL + 1]);
  fp J_ca4cam_dyadSL = 1e-3f * (k2Boff * initvalu[initvalu_offset_Dyad + 2] - k4Bon * Bdyad * initvalu[initvalu_offset_SL + 2]);

  fp J_cam_SLmyo = kSLmyo * (initvalu[initvalu_offset_SL + 0] - initvalu[initvalu_offset_Cyt + 0]);
  fp J_ca2cam_SLmyo = kSLmyo * (initvalu[initvalu_offset_SL + 1] - initvalu[initvalu_offset_Cyt + 1]);
  fp J_ca4cam_SLmyo = kSLmyo * (initvalu[initvalu_offset_SL + 2] - initvalu[initvalu_offset_Cyt + 2]);

  finavalu[initvalu_offset_Dyad + 0] = finavalu[initvalu_offset_Dyad + 0] - J_cam_dyadSL;
  finavalu[initvalu_offset_Dyad + 1] = finavalu[initvalu_offset_Dyad + 1] - J_ca2cam_dyadSL;
  finavalu[initvalu_offset_Dyad + 2] = finavalu[initvalu_offset_Dyad + 2] - J_ca4cam_dyadSL;

  finavalu[initvalu_offset_SL + 0] = finavalu[initvalu_offset_SL + 0] + J_cam_dyadSL * Vdyad / VSL - J_cam_SLmyo / VSL;
  finavalu[initvalu_offset_SL + 1] = finavalu[initvalu_offset_SL + 1] + J_ca2cam_dyadSL * Vdyad / VSL - J_ca2cam_SLmyo / VSL;
  finavalu[initvalu_offset_SL + 2] = finavalu[initvalu_offset_SL + 2] + J_ca4cam_dyadSL * Vdyad / VSL - J_ca4cam_SLmyo / VSL;

  finavalu[initvalu_offset_Cyt + 0] = finavalu[initvalu_offset_Cyt + 0] + J_cam_SLmyo / Vmyo;
  finavalu[initvalu_offset_Cyt + 1] = finavalu[initvalu_offset_Cyt + 1] + J_ca2cam_SLmyo / Vmyo;
  finavalu[initvalu_offset_Cyt + 2] = finavalu[initvalu_offset_Cyt + 2] + J_ca4cam_SLmyo / Vmyo;
}

void kernel_fin(fp *initvalu,
                int initvalu_offset_ecc,
                int initvalu_offset_Dyad,
                int initvalu_offset_SL,
                int initvalu_offset_Cyt,
                fp *parameter,
                fp *finavalu,
                fp JCaDyad,
                fp JCaSL,
                fp JCaCyt) {
  fp com[3];
  com[0] = JCaDyad;
  com[1] = JCaSL;
  com[2] = JCaCyt;
  kernel_fin_2(0, initvalu, finavalu, initvalu_offset_ecc, initvalu_offset_Dyad, initvalu_offset_SL, initvalu_offset_Cyt, parameter, com);
}

__global__ void kernel(fp timeinst,
                       fp *initvalu,
                       fp *finavalu,
                       fp *params,
                       fp *com) {
  if (blockIdx.x == 0 && threadIdx.x == 0) {
    for (int i = 0; i < EQUATIONS; i++) finavalu[i] = 0.0f;

    kernel_ecc_2(timeinst, initvalu, finavalu, 0, params);

    fp CaDyad = initvalu[35] * 1e3f;
    kernel_cam_2(timeinst, initvalu, finavalu, 46, params, 1, com, 0, CaDyad);

    fp CaSL = initvalu[36] * 1e3f;
    kernel_cam_2(timeinst, initvalu, finavalu, 61, params, 6, com, 1, CaSL);

    fp CaCyt = initvalu[37] * 1e3f;
    kernel_cam_2(timeinst, initvalu, finavalu, 76, params, 11, com, 2, CaCyt);

    for (int i = 0; i < EQUATIONS; i++) {
      if (isnan(finavalu[i]) || isinf(finavalu[i])) finavalu[i] = 0.0001f;
    }
  }
}

