#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <cuda_runtime.h>

#ifndef fp
#define fp float
#endif

#ifndef EQUATIONS
#define EQUATIONS 91
#endif

#ifndef PARAMETERS
#define PARAMETERS 16
#endif

#define ATTEMPTS 12
#define MIN_SCALE_FACTOR 0.125f
#define MAX_SCALE_FACTOR 4.0f

extern void read(char* filename, fp* input, int data_rows, int data_cols, int major);
extern long long get_time();

extern void embedded_fehlberg_7_8(fp timeinst,
                                  fp h,
                                  fp* initvalu,
                                  fp* finavalu,
                                  fp* error,
                                  fp* parameter,
                                  fp* com,
                                  fp* d_initvalu,
                                  fp* d_finavalu,
                                  fp* d_params,
                                  fp* d_com);

int solver(fp** y, fp* x, int xmax, fp* params, int mode) {
  fp err_exponent = 1.0f / 7.0f;
  fp last_interval = 0;
  int error, outside;
  fp h_init = 1, h = h_init;
  fp tolerance;
  int xmin = 0;

  fp scale_min, scale_fina;
  fp* err = (fp*)malloc(EQUATIONS * sizeof(fp));
  fp* scale = (fp*)malloc(EQUATIONS * sizeof(fp));
  fp* yy = (fp*)malloc(EQUATIONS * sizeof(fp));
  fp* com = (fp*)malloc(3 * sizeof(fp));

  fp *d_initvalu = NULL, *d_finavalu = NULL, *d_params = NULL, *d_com = NULL;
  cudaMalloc((void**)&d_initvalu, EQUATIONS * sizeof(fp));
  cudaMalloc((void**)&d_finavalu, EQUATIONS * sizeof(fp));
  cudaMalloc((void**)&d_params, PARAMETERS * sizeof(fp));
  cudaMalloc((void**)&d_com, 3 * sizeof(fp));

  int i, j, k;
  tolerance = 10 / (fp)(xmax - xmin);
  x[0] = 0;

  if (xmax < xmin || h <= 0.0f) {
    cudaFree(d_initvalu); cudaFree(d_finavalu); cudaFree(d_params); cudaFree(d_com);
    free(err); free(scale); free(yy); free(com);
    return -2;
  }
  if (xmax == xmin) {
    cudaFree(d_initvalu); cudaFree(d_finavalu); cudaFree(d_params); cudaFree(d_com);
    free(err); free(scale); free(yy); free(com);
    return 0;
  }
  if (h > (xmax - xmin)) {
    h = (fp)xmax - (fp)xmin;
    last_interval = 1;
  }

  for (k = 1; k <= xmax; k++) {
    x[k] = k - 1;
    h = h_init;
    scale_fina = 1.0f;

    for (j = 0; j < ATTEMPTS; j++) {
      error = 0;
      outside = 0;
      scale_min = MAX_SCALE_FACTOR;

      embedded_fehlberg_7_8(x[k], h, y[k - 1], y[k], err, params, com, d_initvalu, d_finavalu, d_params, d_com);

      for (i = 0; i < EQUATIONS; i++) {
        if (err[i] > 0) error = 1;
      }
      if (error != 1) {
        scale_fina = MAX_SCALE_FACTOR;
        break;
      }

      for (i = 0; i < EQUATIONS; i++) {
        if (y[k - 1][i] == 0.0f) yy[i] = tolerance;
        else yy[i] = fabsf(y[k - 1][i]);
        scale[i] = 0.8f * powf(tolerance * yy[i] / err[i], err_exponent);
        if (scale[i] < scale_min) scale_min = scale[i];
      }
      scale_fina = (scale_min < MIN_SCALE_FACTOR ? MIN_SCALE_FACTOR : (scale_min > MAX_SCALE_FACTOR ? MAX_SCALE_FACTOR : scale_min));

      for (i = 0; i < EQUATIONS; i++) {
        if (err[i] > (tolerance * yy[i])) outside = 1;
      }
      if (outside == 0) break;

      h = h * scale_fina;
      if (h >= 0.9f) h = 0.9f;
      if (x[k] + h > (fp)xmax) h = (fp)xmax - x[k];
      else if (x[k] + h + 0.5f * h > (fp)xmax) h = 0.5f * h;
    }

    x[k] = x[k] + h;
    if (j >= ATTEMPTS) {
      cudaFree(d_initvalu); cudaFree(d_finavalu); cudaFree(d_params); cudaFree(d_com);
      free(err); free(scale); free(yy); free(com);
      return -1;
    }
  }

  cudaFree(d_initvalu); cudaFree(d_finavalu); cudaFree(d_params); cudaFree(d_com);
  free(err); free(scale); free(yy); free(com);
  return 0;
}

int main(int argc, char *argv[]) {
  long long time0 = get_time();
  long long time1, time2, time3, time4, time5;

  long long memory;
  int i, j;
  int status;
  int mode;

  long workload, xmin, xmax;
  fp h, tolerance;

  fp*** y;
  fp** x;
  fp** params;

  int threads;

  if (argc != 5) {
    printf("ERROR: %d is the incorrect number of arguments, the number of arguments must be 4\n", argc - 1);
    return 0;
  } else {
    xmax = atoi(argv[1]);
    if (xmax < 0) {
      printf("ERROR: %d is the incorrect end of simulation interval, use numbers > 0\n", (int)xmax);
      return 0;
    }

    workload = atoi(argv[2]);
    if (workload < 0) {
      printf("ERROR: %d is the incorrect number of instances of simulation, use numbers > 0\n", (int)workload);
      return 0;
    }

    mode = atoi(argv[3]);
    if (mode != 0 && mode != 1) {
      printf("ERROR: %d is the incorrect mode, it should be omitted or equal to 0 or 1\n", mode);
      return 0;
    }

    threads = atoi(argv[4]);
    if (threads < 0) {
      printf("ERROR: %d is the incorrect number of threads, use numbers > 0\n", threads);
      return 0;
    }
  }

  time1 = get_time();

  memory = workload * (xmax + 1) * EQUATIONS * 4;
  if (memory > 1000000000) {
    printf("ERROR: trying to allocate more than 1.0GB of memory, decrease workload and span parameters or change memory parameter\n");
    return 0;
  }

  y = (fp***)malloc(workload * sizeof(fp**));
  for (i = 0; i < workload; i++) {
    y[i] = (fp**)malloc((1 + xmax) * sizeof(fp*));
    for (j = 0; j < (1 + xmax); j++) {
      y[i][j] = (fp*)malloc(EQUATIONS * sizeof(fp));
    }
  }

  x = (fp**)malloc(workload * sizeof(fp*));
  for (i = 0; i < workload; i++) x[i] = (fp*)malloc((1 + xmax) * sizeof(fp));

  params = (fp**)malloc(workload * sizeof(fp*));
  for (i = 0; i < workload; i++) params[i] = (fp*)malloc(PARAMETERS * sizeof(fp));

  time2 = get_time();

  for (i = 0; i < workload; i++) {
    read((char*)"../../data/myocyte/y.txt", y[i][0], 91, 1, 0);
  }
  for (i = 0; i < workload; i++) {
    read((char*)"../../data/myocyte/params.txt", params[i], 16, 1, 0);
  }

  time3 = get_time();

  for (i = 0; i < workload; i++) {
    status = solver(y[i], x[i], xmax, params[i], mode);
    (void)status;
  }

  time4 = get_time();

  for (i = 0; i < workload; i++) {
    for (j = 0; j < (1 + xmax); j++) free(y[i][j]);
    free(y[i]);
  }
  free(y);

  for (i = 0; i < workload; i++) free(x[i]);
  free(x);

  for (i = 0; i < workload; i++) free(params[i]);
  free(params);

  time5 = get_time();

  printf("Time spent in different stages of the application:\n");
  printf("%.12f s, %.12f % : SETUP VARIABLES, READ COMMAND LINE ARGUMENTS\n", (float)(time1 - time0) / 1000000, (float)(time1 - time0) / (float)(time5 - time0) * 100);
  printf("%.12f s, %.12f % : ALLOCATE MEMORY\n", (float)(time2 - time1) / 1000000, (float)(time2 - time1) / (float)(time5 - time0) * 100);
  printf("%.12f s, %.12f % : READ DATA FROM FILES\n", (float)(time3 - time2) / 1000000, (float)(time3 - time2) / (float)(time5 - time0) * 100);
  printf("%.12f s, %.12f % : RUN COMPUTATION\n", (float)(time4 - time3) / 1000000, (float)(time4 - time3) / (float)(time5 - time0) * 100);
  printf("%.12f s, %.12f % : FREE MEMORY\n", (float)(time5 - time4) / 1000000, (float)(time5 - time4) / (float)(time5 - time0) * 100);
  printf("Total time:\n");
  printf("%.12f s\n", (float)(time5 - time0) / 1000000);

  return 0;
}

