#include <math.h>
#include <sys/time.h>
#include <time.h>
#include <cuda_runtime.h>

#define MAX_ARGS 10
#define REC_LENGTH 49
#define REC_WINDOW 10
#define LATITUDE_POS 28
#define OPEN 10000

struct neighbor {
    char entry[REC_LENGTH];
    double dist;
};

__device__ float parse_float_simple(const char* s) {
    int i = 0;
    while (s[i] == ' ' || s[i] == '\t' || s[i] == '\n' || s[i] == '\r') i++;

    int sign = 1;
    if (s[i] == '-') {
        sign = -1;
        i++;
    } else if (s[i] == '+') {
        i++;
    }

    float val = 0.0f;
    while (s[i] >= '0' && s[i] <= '9') {
        val = val * 10.0f + (float)(s[i] - '0');
        i++;
    }

    if (s[i] == '.') {
        i++;
        float place = 0.1f;
        while (s[i] >= '0' && s[i] <= '9') {
            val += (float)(s[i] - '0') * place;
            place *= 0.1f;
            i++;
        }
    }

    return sign * val;
}

__global__ void compute_distances(const char* sandbox, float* z, int rec_count, float target_lat, float target_long) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < rec_count) {
        const char* rec_iter = sandbox + (i * REC_LENGTH + LATITUDE_POS - 1);
        float tmp_lat = parse_float_simple(rec_iter);
        float tmp_long = parse_float_simple(rec_iter + 5);
        float dlat = tmp_lat - target_lat;
        float dlong = tmp_long - target_long;
        z[i] = sqrtf(dlat * dlat + dlong * dlong);
    }
}

int main(int argc, char* argv[]) {
