    cudaMemcpy(d_input_itemsets, input_itemsets, transfer_size * sizeof(int), cudaMemcpyHostToDevice);
    cudaMemcpy(d_referrence, referrence, transfer_size * sizeof(int), cudaMemcpyHostToDevice);

    int block_width = (max_cols - 1) / BLOCK_SIZE;
    const int threads = 256;

    for (int blk = 1; blk <= block_width; blk++) {
        int tiles = blk;
        int grid = (tiles + threads - 1) / threads;
        nw_top_left_kernel<<<grid, threads>>>(d_input_itemsets, d_referrence, max_cols, penalty, blk);
    }

    printf("Processing bottom-right matrix\n");

    for (int blk = 2; blk <= block_width; blk++) {
        int tiles = block_width - (blk - 1);
        int grid = (tiles + threads - 1) / threads;
        nw_bottom_right_kernel<<<grid, threads>>>(d_input_itemsets, d_referrence, max_cols, penalty, blk, block_width);
    }

    cudaMemcpy(input_itemsets, d_input_itemsets, transfer_size * sizeof(int), cudaMemcpyDeviceToHost);

    cudaFree(d_input_itemsets);
    cudaFree(d_referrence);
}

