    cuda_check(cudaMalloc((void**)&d_c, size_I * sizeof(float)), "cudaMalloc d_c");
    cuda_check(cudaMalloc((void**)&d_dN, size_I * sizeof(float)), "cudaMalloc d_dN");
    cuda_check(cudaMalloc((void**)&d_dS, size_I * sizeof(float)), "cudaMalloc d_dS");
    cuda_check(cudaMalloc((void**)&d_dW, size_I * sizeof(float)), "cudaMalloc d_dW");
    cuda_check(cudaMalloc((void**)&d_dE, size_I * sizeof(float)), "cudaMalloc d_dE");

    cuda_check(cudaMemcpy(d_J, J, size_I * sizeof(float), cudaMemcpyHostToDevice), "memcpy J H2D");

    printf("Start the SRAD main loop\n");

#ifdef ITERATION
    for (iter = 0; iter < niter; iter++) {
#endif
