  float result=0.0;
  for (i=0;i<dim;i++)
    result += (p1.coord[i] - p2.coord[i])*(p1.coord[i] - p2.coord[i]);
#ifdef INSERT_WASTE
  double s = waste(result);
  result += s;
  result -= s;
#endif
  return(result);
}

__device__ inline float dist_dev(const Point& p1, const Point& p2, int dim) {
  float result = 0.0f;
  for (int i = 0; i < dim; i++) {
    float d = p1.coord[i] - p2.coord[i];
    result += d * d;
  }
  return result;
}

__global__ void pgain_dist_kernel(Point* p, long x, int dim, long k1, long k2,
                                  bool* switch_membership_d, int* center_table_d,
                                  double* lower, double* cost_of_opening_x) {
  long idx = k1 + blockIdx.x * blockDim.x + threadIdx.x;
  if (idx >= k2) return;

  float x_cost = dist_dev(p[idx], p[x], dim) * p[idx].weight;
  float current_cost = p[idx].cost;

  if (x_cost < current_cost) {
    switch_membership_d[idx] = 1;
    atomicAdd(cost_of_opening_x, (double)(x_cost - current_cost));
  } else {
    int assign = (int)p[idx].assign;
    int cidx = center_table_d[assign];
    atomicAdd(&lower[cidx], (double)(current_cost - x_cost));
  }
}

__global__ void pgain_apply_kernel(Point* p, long x, int dim, long k1, long k2,
                                   bool* switch_membership_d, int* center_table_d,
                                   double* gl_lower) {
  long idx = k1 + blockIdx.x * blockDim.x + threadIdx.x;
  if (idx >= k2) return;

  bool close_center = gl_lower[center_table_d[(int)p[idx].assign]] > 0;
  if (switch_membership_d[idx] || close_center) {
    p[idx].cost = p[idx].weight * dist_dev(p[idx], p[x], dim);
    p[idx].assign = x;
  }
}

float pspeedy(Points *points, float z, long *kcenter, int pid, pthread_barrier_t* barrier)
{
#ifdef PROFILE
  double t1 = gettime();
#endif

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  long bsize = points->num/nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if( pid == nproc-1 ) k2 = points->num;

  static double totalcost;
  static bool open = false;
  static double* costs;
  static int i;

#ifdef ENABLE_THREADS
  static pthread_mutex_t mutex = PTHREAD_MUTEX_INITIALIZER;
  static pthread_cond_t cond = PTHREAD_COND_INITIALIZER;
#endif

#ifdef PRINTINFO
  if( pid == 0 ){
    fprintf(stderr, "Speedy: facility cost %lf\n", z);
  }
#endif

  for( int k = (int)k1; k < (int)k2; k++ ) {
    float distance = dist(points->p[k],points->p[0],points->dim);
    points->p[k].cost = distance * points->p[k].weight;
    points->p[k].assign=0;
  }

  if( pid==0 ) {
    *kcenter = 1;
    costs = (double*)malloc(sizeof(double)*nproc);
  }

  if( pid != 0 ) {
    while(1) {
#ifdef ENABLE_THREADS
      pthread_mutex_lock(&mutex);
      while(!open) pthread_cond_wait(&cond,&mutex);
      pthread_mutex_unlock(&mutex);
#endif
      if( i >= points->num ) break;
      for( int k = (int)k1; k < (int)k2; k++ ) {
        float distance = dist(points->p[i],points->p[k],points->dim);
        if( distance*points->p[k].weight < points->p[k].cost ) {
          points->p[k].cost = distance * points->p[k].weight;
          points->p[k].assign=i;
        }
      }
#ifdef ENABLE_THREADS
      pthread_barrier_wait(barrier);
      pthread_barrier_wait(barrier);
#endif
    }
  } else {
    for(i = 1; i < points->num; i++ ) {
      bool to_open = ((float)lrand48()/(float)INT_MAX)<(points->p[i].cost/z);
      if( to_open ) {
        (*kcenter)++;
#ifdef ENABLE_THREADS
        pthread_mutex_lock(&mutex);
#endif
        open = true;
#ifdef ENABLE_THREADS
        pthread_mutex_unlock(&mutex);
        pthread_cond_broadcast(&cond);
#endif
        for( int k = (int)k1; k < (int)k2; k++ ) {
          float distance = dist(points->p[i],points->p[k],points->dim);
          if( distance*points->p[k].weight < points->p[k].cost ) {
            points->p[k].cost = distance * points->p[k].weight;
            points->p[k].assign=i;
          }
        }
#ifdef ENABLE_THREADS
        pthread_barrier_wait(barrier);
#endif
        open = false;
#ifdef ENABLE_THREADS
        pthread_barrier_wait(barrier);
#endif
      }
    }
#ifdef ENABLE_THREADS
    pthread_mutex_lock(&mutex);
#endif
    open = true;
#ifdef ENABLE_THREADS
    pthread_mutex_unlock(&mutex);
    pthread_cond_broadcast(&cond);
#endif
  }
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif
  open = false;
  double mytotal = 0;
  for( int k = (int)k1; k < (int)k2; k++ ) {
    mytotal += points->p[k].cost;
  }
  costs[pid] = mytotal;
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  if( pid == 0 ) {
    totalcost=z*(*kcenter);
    for( int i2 = 0; i2 < nproc; i2++ ) {
      totalcost += costs[i2];
    }
    free(costs);
  }
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

#ifdef PRINTINFO
  if( pid == 0 ) {
    fprintf(stderr, "Speedy opened %d facilities for total cost %lf\n",
            *kcenter, totalcost);
    fprintf(stderr, "Distance Cost %lf\n", totalcost - z*(*kcenter));
  }
#endif

#ifdef PROFILE
  double t2 = gettime();
  if( pid== 0 ) {
    time_speedy += t2 -t1;
  }
#endif
  return(totalcost);
}

double pgain(long x, Points *points, double z, long int *numcenters, int pid, pthread_barrier_t* barrier)
{
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif
#ifdef PROFILE
  double t0 = gettime();
#endif

  long bsize = points->num/nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if( pid == nproc-1 ) k2 = points->num;

  int number_of_centers_to_close = 0;

  static double *work_mem;
  static double gl_cost_of_opening_x;
  static int gl_number_of_centers_to_close;

  int stride = (int)(*numcenters)+2;
  int cl = CACHE_LINE/sizeof(double);
  if( stride % cl != 0 ) {
    stride = cl * ( stride / cl + 1);
  }
  int K = stride -2;

  double cost_of_opening_x = 0;

  if( pid==0 ) {
    cudaCheck(cudaMallocManaged((void**)&work_mem, stride*(nproc+1)*sizeof(double)), "cudaMallocManaged work_mem");
    gl_cost_of_opening_x = 0;
    gl_number_of_centers_to_close = 0;
  }
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  int count = 0;
  for( int i = (int)k1; i < (int)k2; i++ ) {
    if( is_center[i] ) {
      center_table[i] = count++;
    }
  }
  work_mem[pid*stride] = count;

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  if( pid == 0 ) {
    int accum = 0;
    for( int p = 0; p < nproc; p++ ) {
      int tmp = (int)work_mem[p*stride];
      work_mem[p*stride] = accum;
      accum += tmp;
    }
  }

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  for( int i = (int)k1; i < (int)k2; i++ ) {
    if( is_center[i] ) {
      center_table[i] += (int)work_mem[pid*stride];
    }
  }

  memset(switch_membership + k1, 0, (k2-k1)*sizeof(bool));
  memset(work_mem+pid*stride, 0, stride*sizeof(double));
  if( pid== 0 ) memset(work_mem+nproc*stride,0,stride*sizeof(double));

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif
#ifdef PROFILE
  double t1 = gettime();
  if( pid == 0 ) time_gain_init += t1-t0;
#endif

  double* lower = &work_mem[pid*stride];
  double* gl_lower = &work_mem[nproc*stride];

  double* d_cost_of_opening_x = nullptr;
  cudaCheck(cudaMallocManaged((void**)&d_cost_of_opening_x, sizeof(double)), "cudaMallocManaged d_cost_of_opening_x");
  *d_cost_of_opening_x = 0.0;

  int threads = 256;
  int blocks = (int)((k2 - k1 + threads - 1) / threads);
  if (blocks > 0) {
    pgain_dist_kernel<<<blocks, threads>>>(points->p, x, points->dim, k1, k2,
                                           switch_membership, center_table,
                                           lower, d_cost_of_opening_x);
    cudaCheck(cudaGetLastError(), "pgain_dist_kernel launch");
    cudaCheck(cudaDeviceSynchronize(), "pgain_dist_kernel sync");
  }
  cost_of_opening_x = *d_cost_of_opening_x;
  cudaCheck(cudaFree(d_cost_of_opening_x), "cudaFree d_cost_of_opening_x");

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif
#ifdef PROFILE
  double t2 = gettime();
  if( pid==0){
    time_gain_dist += t2 - t1;
  }
#endif

  for ( int i = (int)k1; i < (int)k2; i++ ) {
    if( is_center[i] ) {
      double low = z;
      for( int p = 0; p < nproc; p++ ) {
        low += work_mem[center_table[i]+p*stride];
      }
      gl_lower[center_table[i]] = low;

      if ( low > 0 ) {
        ++number_of_centers_to_close;
        cost_of_opening_x -= low;
      }
    }
  }
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  work_mem[pid*stride + K] = number_of_centers_to_close;
  work_mem[pid*stride + K+1] = cost_of_opening_x;

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  if( pid==0 ) {
    gl_cost_of_opening_x = z;
    for( int p = 0; p < nproc; p++ ) {
      gl_number_of_centers_to_close += (int)work_mem[p*stride + K];
      gl_cost_of_opening_x += work_mem[p*stride+K+1];
    }
  }
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  if ( gl_cost_of_opening_x < 0 ) {
    if (blocks > 0) {
      pgain_apply_kernel<<<blocks, threads>>>(points->p, x, points->dim, k1, k2,
                                              switch_membership, center_table,
                                              gl_lower);
      cudaCheck(cudaGetLastError(), "pgain_apply_kernel launch");
      cudaCheck(cudaDeviceSynchronize(), "pgain_apply_kernel sync");
    }

    for( int i = (int)k1; i < (int)k2; i++ ) {
      if( is_center[i] && gl_lower[center_table[i]] > 0 ) {
        is_center[i] = false;
      }
    }
    if( x >= k1 && x < k2 ) {
      is_center[x] = true;
    }

    if( pid==0 ) {
      *numcenters = *numcenters + 1 - gl_number_of_centers_to_close;
    }
  } else {
    if( pid==0 )
      gl_cost_of_opening_x = 0;
  }
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif
  if( pid == 0 ) {
    cudaCheck(cudaFree(work_mem), "cudaFree work_mem");
  }

#ifdef PROFILE
  double t3 = gettime();
  if( pid==0 )
    time_gain += t3-t0;
#endif

  return -gl_cost_of_opening_x;
}

float pFL(Points *points, int *feasible, int numfeasible,
          float z, long *k, double cost, long iter, float e,
          int pid, pthread_barrier_t* barrier)
{
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif
  long i;
  double change;
  long numberOfPoints;

  change = cost;

  while (change/cost > 1.0*e) {
    change = 0.0;
    numberOfPoints = points->num;
    (void)numberOfPoints;

    if( pid == 0 ) {
      intshuffle(feasible, numfeasible);
    }
#ifdef ENABLE_THREADS
    pthread_barrier_wait(barrier);
#endif
    for (i=0;i<iter;i++) {
      long x = i%numfeasible;
      change += pgain(feasible[x], points, z, k, pid, barrier);
      c++;
    }

    cost -= change;
#ifdef PRINTINFO
    if( pid == 0 ) {
      fprintf(stderr, "%d centers, cost %lf, total distance %lf\n",
              *k, cost, cost - z*(*k));
    }
#endif
#ifdef ENABLE_THREADS
    pthread_barrier_wait(barrier);
#endif
  }
  return(cost);
}

int selectfeasible_fast(Points *points, int **feasible, int kmin, int pid, pthread_barrier_t* barrier)
{
#ifdef PROFILE
  double t1 = gettime();
#endif

  int numfeasible = (int)points->num;
  if (numfeasible > (ITER*kmin*log((double)kmin)))
    numfeasible = (int)(ITER*kmin*log((double)kmin));
  *feasible = (int *)malloc(numfeasible*sizeof(int));

  float* accumweight;
  float totalweight;

  long k1 = 0;
  long k2 = numfeasible;

  float w;
  int l,r,k;

  if (numfeasible == points->num) {
    for (int i=(int)k1;i<(int)k2;i++)
      (*feasible)[i] = i;
    return numfeasible;
  }

  accumweight= (float*)malloc(sizeof(float)*points->num);
  accumweight[0] = points->p[0].weight;
  totalweight=0;
  for( int i = 1; i < points->num; i++ ) {
    accumweight[i] = accumweight[i-1] + points->p[i].weight;
  }
  totalweight=accumweight[points->num-1];

  for(int i=(int)k1; i<(int)k2; i++ ) {
    w = (lrand48()/(float)INT_MAX)*totalweight;

    l=0;
    r=(int)points->num-1;
    if( accumweight[0] > w )  {
      (*feasible)[i]=0;
      continue;
    }
    while( l+1 < r ) {
      k = (l+r)/2;
      if( accumweight[k] > w ) {
        r = k;
      }
      else {
        l=k;
      }
    }
    (*feasible)[i]=r;
  }

  free(accumweight);

#ifdef PROFILE
  double t2 = gettime();
  time_select_feasible += t2-t1;
#endif
  return numfeasible;
}

float pkmedian(Points *points, long kmin, long kmax, long* kfinal,
               int pid, pthread_barrier_t* barrier )
{
  int i;
  double cost;
  double lastcost;
  double hiz, loz, z;

  static long k;
  static int *feasible;
  static int numfeasible;
  static double* hizs;

  if( pid==0 ) hizs = (double*)calloc(nproc,sizeof(double));
  hiz = loz = 0.0;
  long numberOfPoints = points->num;
  long ptDimension = points->dim;

  long bsize = points->num/nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if( pid == nproc-1 ) k2 = points->num;

#ifdef PRINTINFO
  if( pid == 0 )
    {
      printf("Starting Kmedian procedure\n");
      printf("%i points in %i dimensions\n", numberOfPoints, ptDimension);
    }
#endif

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  double myhiz = 0;
  for (long kk=k1;kk < k2; kk++ ) {
    myhiz += dist(points->p[kk], points->p[0], ptDimension)*points->p[kk].weight;
  }
  hizs[pid] = myhiz;

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  for( int ii = 0; ii < nproc; ii++ ) {
    hiz += hizs[ii];
  }

  loz=0.0; z = (hiz+loz)/2.0;

  if (points->num <= kmax) {
    for (long kk=k1;kk<k2;kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0;
    }
    cost = 0;
    if( pid== 0 ) {
      free(hizs);
      *kfinal = k;
    }
    return (float)cost;
  }

  if( pid == 0 ) shuffle(points);
  cost = pspeedy(points, (float)z, &k, pid, barrier);

#ifdef PRINTINFO
  if( pid == 0 )
    printf("thread %d: Finished first call to speedy, cost=%lf, k=%i\n",pid,cost,k);
#endif
  i=0;

  while ((k < kmin)&&(i<SP)) {
    cost = pspeedy(points, (float)z, &k, pid, barrier);
    i++;
  }

#ifdef PRINTINFO
  if( pid==0)
    printf("thread %d: second call to speedy, cost=%lf, k=%d\n",pid,cost,k);
#endif

  while (k < kmin) {
#ifdef PRINTINFO
    if( pid == 0 ) {
      printf("%lf %lf\n", loz, hiz);
      printf("Speedy indicates we should try lower z\n");
    }
#endif
    if (i >= SP) {hiz=z; z=(hiz+loz)/2.0; i=0;}
    if( pid == 0 ) shuffle(points);
    cost = pspeedy(points, (float)z, &k, pid, barrier);
    i++;
  }

  if( pid == 0 ) {
    numfeasible = selectfeasible_fast(points,&feasible,(int)kmin,pid,barrier);
    for( int ii = 0; ii< points->num; ii++ ) {
      is_center[points->p[ii].assign]= true;
    }
  }

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  while(1) {
    d++;
#ifdef PRINTINFO
    if( pid==0 ) {
      printf("loz = %lf, hiz = %lf\n", loz, hiz);
      printf("Running Local Search...\n");
    }
#endif

    lastcost = cost;
    (void)lastcost;
    cost = pFL(points, feasible, numfeasible, (float)z, &k, cost,
               (long)(ITER*kmax*log((double)kmax)), 0.1f, pid, barrier);

    if (((k <= (1.1)*kmax)&&(k >= (0.9)*kmin))||
        ((k <= kmax+2)&&(k >= kmin-2))) {
#ifdef PRINTINFO
      if( pid== 0) {
        printf("Trying a more accurate local search...\n");
      }
#endif
      cost = pFL(points, feasible, numfeasible, (float)z, &k, cost,
                 (long)(ITER*kmax*log((double)kmax)), 0.001f, pid, barrier);
    }

    if (k > kmax) {
      loz = z; z = (hiz+loz)/2.0;
      cost += (z-loz)*k;
    }
    if (k < kmin) {
      hiz = z; z = (hiz+loz)/2.0;
      cost += (z-hiz)*k;
    }

    if (((k <= kmax)&&(k >= kmin))||((loz >= (0.999)*hiz)) ) {
      break;
    }
#ifdef ENABLE_THREADS
    pthread_barrier_wait(barrier);
#endif
  }

  if( pid==0 ) {
    free(feasible);
    free(hizs);
    *kfinal = k;
  }

  return (float)cost;
}

int contcenters(Points *points)
{
  long i, ii;
  float relweight;

  for (i=0;i<points->num;i++) {
    if (points->p[i].assign != i) {
      relweight=points->p[points->p[i].assign].weight + points->p[i].weight;
      relweight = points->p[i].weight/relweight;
      for (ii=0;ii<points->dim;ii++) {
        points->p[points->p[i].assign].coord[ii]*=1.0-relweight;
        points->p[points->p[i].assign].coord[ii]+= points->p[i].coord[ii]*relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }

  return 0;
}

void copycenters(Points *points, Points* centers, long* centerIDs, long offset)
{
  long i;
  long k;

  bool *is_a_median = (bool *) calloc(points->num, sizeof(bool));

  for ( i = 0; i < points->num; i++ ) {
    is_a_median[points->p[i].assign] = 1;
  }

  k=centers->num;

  for ( i = 0; i < points->num; i++ ) {
    if ( is_a_median[i] ) {
      memcpy( centers->p[k].coord, points->p[i].coord, points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }

  centers->num = k;

  free(is_a_median);
}

struct pkmedian_arg_t
{
  Points* points;
  long kmin;
  long kmax;
  long* kfinal;
  int pid;
  pthread_barrier_t* barrier;
};

void* localSearchSub(void* arg_) {
  pkmedian_arg_t* arg= (pkmedian_arg_t*)arg_;
  pkmedian(arg->points,arg->kmin,arg->kmax,arg->kfinal,arg->pid,arg->barrier);
  return NULL;
}

void localSearch( Points* points, long kmin, long kmax, long* kfinal ) {
#ifdef PROFILE
  double t1 = gettime();
#endif

  pthread_barrier_t barrier;
#ifdef ENABLE_THREADS
  pthread_barrier_init(&barrier,NULL,nproc);
#endif
  pthread_t* threads = new pthread_t[nproc];
  pkmedian_arg_t* arg = new pkmedian_arg_t[nproc];

  for( int i = 0; i < nproc; i++ ) {
    arg[i].points = points;
    arg[i].kmin = kmin;
    arg[i].kmax = kmax;
    arg[i].pid = i;
    arg[i].kfinal = kfinal;

    arg[i].barrier = &barrier;
#ifdef ENABLE_THREADS
    pthread_create(threads+i,NULL,localSearchSub,(void*)&arg[i]);
#else
    localSearchSub(&arg[0]);
#endif
  }

  for ( int i = 0; i < nproc; i++) {
#ifdef ENABLE_THREADS
    pthread_join(threads[i],NULL);
#endif
  }

  delete[] threads;
  delete[] arg;
#ifdef ENABLE_THREADS
  pthread_barrier_destroy(&barrier);
#endif

#ifdef PROFILE
  double t2 = gettime();
  time_local_search += t2-t1;
#endif
}

class PStream {
public:
  virtual size_t read( float* dest, int dim, int num ) = 0;
  virtual int ferror() = 0;
  virtual int feof() = 0;
  virtual ~PStream() {
  }
};

class SimStream : public PStream {
public:
  SimStream(long n_ ) {
    n = n_;
  }
  size_t read( float* dest, int dim, int num ) {
    size_t count = 0;
    for( int i = 0; i < num && n > 0; i++ ) {
      for( int k = 0; k < dim; k++ ) {
        dest[i*dim + k] = lrand48()/(float)INT_MAX;
      }
      n--;
      count++;
    }
    return count;
  }
  int ferror() {
    return 0;
  }
  int feof() {
    return n <= 0;
  }
  ~SimStream() {
  }
private:
  long n;
};

class FileStream : public PStream {
public:
  FileStream(char* filename) {
    fp = fopen( filename, "rb");
    if( fp == NULL ) {
      fprintf(stderr,"error opening file %s\n.",filename);
      exit(1);
    }
  }
  size_t read( float* dest, int dim, int num ) {
    return std::fread(dest, sizeof(float)*dim, num, fp);
  }
  int ferror() {
    return std::ferror(fp);
  }
  int feof() {
    return std::feof(fp);
  }
  ~FileStream() {
    printf("closing file stream\n");
    fclose(fp);
  }
private:
  FILE* fp;
};

void outcenterIDs( Points* centers, long* centerIDs, char* outfile ) {
  FILE* fp = fopen(outfile, "w");
  if( fp==NULL ) {
    fprintf(stderr, "error opening %s\n",outfile);
    exit(1);
  }
  int* is_a_median = (int*)calloc( sizeof(int), centers->num );
  for( int i =0 ; i< centers->num; i++ ) {
    is_a_median[centers->p[i].assign] = 1;
  }

  for( int i = 0; i < centers->num; i++ ) {
    if( is_a_median[i] ) {
      fprintf(fp, "%u\n", centerIDs[i]);
      fprintf(fp, "%lf\n", centers->p[i].weight);
      for( int k = 0; k < centers->dim; k++ ) {
        fprintf(fp, "%lf ", centers->p[i].coord[k]);
      }
      fprintf(fp,"\n\n");
    }
  }
  fclose(fp);
}

void streamCluster( PStream* stream,
                    long kmin, long kmax, int dim,
                    long chunksize, long centersize, char* outfile )
{
  cudaCheck(cudaMallocManaged((void**)&block, chunksize*dim*sizeof(float)), "cudaMallocManaged block");
  float* centerBlock = nullptr;
  cudaCheck(cudaMallocManaged((void**)&centerBlock, centersize*dim*sizeof(float)), "cudaMallocManaged centerBlock");
  long* centerIDs = (long*)malloc(centersize*dim*sizeof(long));

  if( block == NULL ) {
    fprintf(stderr,"not enough memory for a chunk!\n");
    exit(1);
  }

  Points points;
  points.dim = dim;
  points.num = chunksize;
  cudaCheck(cudaMallocManaged((void**)&points.p, chunksize*sizeof(Point)), "cudaMallocManaged points.p");
  for( int i = 0; i < chunksize; i++ ) {
    points.p[i].coord = &block[i*dim];
  }

  Points centers;
  centers.dim = dim;
  cudaCheck(cudaMallocManaged((void**)&centers.p, centersize*sizeof(Point)), "cudaMallocManaged centers.p");
  centers.num = 0;

  for( int i = 0; i< centersize; i++ ) {
    centers.p[i].coord = &centerBlock[i*dim];
    centers.p[i].weight = 1.0;
  }

  long IDoffset = 0;
  long kfinal;
  while(1) {
    size_t numRead  = stream->read(block, dim, chunksize );
    fprintf(stderr,"read %d points\n",(int)numRead);

    if( stream->ferror() || (numRead < (unsigned int)chunksize && !stream->feof()) ) {
      fprintf(stderr, "error reading data!\n");
      exit(1);
    }

    points.num = (long)numRead;
    for( int i = 0; i < points.num; i++ ) {
      points.p[i].weight = 1.0;
    }

    cudaCheck(cudaMallocManaged((void**)&switch_membership, points.num*sizeof(bool)), "cudaMallocManaged switch_membership");
    cudaCheck(cudaMallocManaged((void**)&is_center, points.num*sizeof(bool)), "cudaMallocManaged is_center");
    cudaCheck(cudaMallocManaged((void**)&center_table, points.num*sizeof(int)), "cudaMallocManaged center_table");
    memset(is_center, 0, points.num*sizeof(bool));

    localSearch(&points,kmin, kmax,&kfinal);

    fprintf(stderr,"finish local search\n");
    contcenters(&points);
    if( kfinal + centers.num > centersize ) {
      fprintf(stderr,"oops! no more space for centers\n");
      exit(1);
    }

#ifdef PRINTINFO
    printf("finish cont center\n");
#endif

    copycenters(&points, &centers, centerIDs, IDoffset);
    IDoffset += (long)numRead;

#ifdef PRINTINFO
    printf("finish copy centers\n");
#endif

    cudaCheck(cudaFree(is_center), "cudaFree is_center");
    cudaCheck(cudaFree(switch_membership), "cudaFree switch_membership");
    cudaCheck(cudaFree(center_table), "cudaFree center_table");

    if( stream->feof() ) {
      break;
    }
  }

  cudaCheck(cudaMallocManaged((void**)&switch_membership, centers.num*sizeof(bool)), "cudaMallocManaged switch_membership centers");
  cudaCheck(cudaMallocManaged((void**)&is_center, centers.num*sizeof(bool)), "cudaMallocManaged is_center centers");
  cudaCheck(cudaMallocManaged((void**)&center_table, centers.num*sizeof(int)), "cudaMallocManaged center_table centers");
  memset(is_center, 0, centers.num*sizeof(bool));

  localSearch( &centers, kmin, kmax ,&kfinal );
  contcenters(&centers);
  outcenterIDs( &centers, centerIDs, outfile);

  cudaCheck(cudaFree(block), "cudaFree block");
  cudaCheck(cudaFree(centerBlock), "cudaFree centerBlock");
  cudaCheck(cudaFree(points.p), "cudaFree points.p");
  cudaCheck(cudaFree(centers.p), "cudaFree centers.p");
  cudaCheck(cudaFree(is_center), "cudaFree is_center final");
  cudaCheck(cudaFree(switch_membership), "cudaFree switch_membership final");
  cudaCheck(cudaFree(center_table), "cudaFree center_table final");
  free(centerIDs);
}

int main(int argc, char **argv)
{
  char *outfilename = new char[MAXNAMESIZE];
  char *infilename = new char[MAXNAMESIZE];
  long kmin, kmax, n, chunksize, clustersize;
  int dim;
  int numthreads;
  (void)numthreads;

  c = 0;
  d = 0;

#ifdef PARSEC_VERSION
#define __PARSEC_STRING(x) #x
#define __PARSEC_XSTRING(x) __PARSEC_STRING(x)
  printf("PARSEC Benchmark Suite Version "__PARSEC_XSTRING(PARSEC_VERSION)"\n");
  fflush(NULL);
#else
  printf("PARSEC Benchmark Suite\n");
  fflush(NULL);
#endif
#ifdef ENABLE_PARSEC_HOOKS
  __parsec_bench_begin(__parsec_streamcluster);
#endif

  if (argc<10) {
    fprintf(stderr,"usage: %s k1 k2 d n chunksize clustersize infile outfile nproc\n", argv[0]);
    fprintf(stderr,"  k1:          Min. number of centers allowed\n");
    fprintf(stderr,"  k2:          Max. number of centers allowed\n");
    fprintf(stderr,"  d:           Dimension of each data point\n");
    fprintf(stderr,"  n:           Number of data points\n");
    fprintf(stderr,"  chunksize:   Number of data points to handle per step\n");
    fprintf(stderr,"  clustersize: Maximum number of intermediate centers\n");
    fprintf(stderr,"  infile:      Input file (if n<=0)\n");
    fprintf(stderr,"  outfile:     Output file\n");
    fprintf(stderr,"  nproc:       Number of threads to use\n");
    fprintf(stderr,"\n");
    fprintf(stderr, "if n > 0, points will be randomly generated instead of reading from infile.\n");
    exit(1);
  }
  kmin = atol(argv[1]);
  kmax = atol(argv[2]);
  dim = atoi(argv[3]);
  n = atol(argv[4]);
  chunksize = atol(argv[5]);
  clustersize = atol(argv[6]);
  strcpy(infilename, argv[7]);
  strcpy(outfilename, argv[8]);
  nproc = atoi(argv[9]);

  ompthreads = nproc;
  nproc = 1;

  srand48(SEED);
  PStream* stream;
  if( n > 0 ) {
    stream = new SimStream(n);
  }
  else {
    stream = new FileStream(infilename);
  }

  double t1 = gettime();

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_begin();
#endif
  streamCluster(stream, kmin, kmax, dim, chunksize, clustersize, outfilename );
#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_end();
#endif

  double t2 = gettime();

  printf("time = %lf\n",t2-t1);

  delete stream;

  printf("time pgain = %lf\n", time_gain);
  printf("time pgain_dist = %lf\n", time_gain_dist);
  printf("time pgain_init = %lf\n", time_gain_init);
  printf("time pselect = %lf\n", time_select_feasible);
  printf("time pspeedy = %lf\n", time_speedy);
  printf("time pshuffle = %lf\n", time_shuffle);
  printf("time localSearch = %lf\n", time_local_search);
  printf("loops=%d\n", d);

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_bench_end();
#endif

  delete[] outfilename;
  delete[] infilename;
  return 0;
}

